// Combine meteo + agenda + mails 24h + telechargements Formaze pour Claude.
const mails = $('Mails des dernieres 24h').all().filter(it => it.json && (it.json.id || it.json.snippet || it.json.subject || it.json.From || it.json.from));
const events = $('Agenda du jour').all().filter(it => it.json && (it.json.start || it.json.id || it.json.summary));
const lignesMails = mails.map((it, i) => {
  const m = it.json;
  const from = m.from?.value?.[0]?.address || m.from?.text || m.From || 'inconnu';
  const sujet = m.subject || m.Subject || '(sans objet)';
  const apercu = (m.snippet || m.textPlain || '').toString().slice(0, 300);
  return `${i + 1}. De: ${from}\n   Objet: ${sujet}\n   Apercu: ${apercu}`;
}).join('\n\n');
const lignesAgenda = events.map((it) => {
  const e = it.json;
  const debut = (e.start && (e.start.dateTime || e.start.date)) || '';
  const heure = e.start && e.start.dateTime ? debut.toString().slice(11, 16) : 'journee';
  const titre = e.summary || '(sans titre)';
  const lieu = e.location ? ` (${e.location})` : '';
  return `- ${heure} : ${titre}${lieu}`;
}).join('\n');
const codes = {0:'ciel degage',1:'plutot ensoleille',2:'partiellement nuageux',3:'couvert',45:'brouillard',48:'brouillard givrant',51:'bruine legere',53:'bruine',55:'bruine forte',61:'pluie faible',63:'pluie',65:'pluie forte',66:'pluie verglacante',67:'pluie verglacante',71:'neige faible',73:'neige',75:'neige forte',77:'neige',80:'averses',81:'averses',82:'fortes averses',85:'averses de neige',86:'averses de neige',95:'orage',96:'orage avec grele',99:'orage avec grele'};
const md = $('Meteo du jour').first()?.json?.daily;
let meteo = 'indisponible';
if (md) {
  const desc = codes[md.weather_code?.[0]] || 'temps variable';
  const tmin = Math.round(md.temperature_2m_min?.[0]);
  const tmax = Math.round(md.temperature_2m_max?.[0]);
  const pluie = md.precipitation_probability_max?.[0];
  meteo = `${desc}, de ${tmin} a ${tmax} degres, risque de pluie ${pluie}%`;
}
const nugetData = $('Telechargements Formaze').first()?.json?.data || [];
const dlFormaze = nugetData.filter(p => (p.id || '').toLowerCase().startsWith('formaze')).reduce((s, p) => s + (p.totalDownloads || 0), 0);
if (mails.length === 0 && events.length === 0) {
  const p = `Tu es l'assistant matinal d'Alexis. Dis bonjour, donne la meteo du jour a Strasbourg en une phrase (${meteo}), precise qu'il n'y a aucun rendez-vous ni mail notable ce matin, puis termine par : Formaze totalise ${dlFormaze} telechargements sur NuGet. Court, en francais, pour une enceinte vocale, sans markdown.`;
  return [{ json: { prompt: p, count: 1 } }];
}
const prompt = `Tu es l'assistant matinal d'Alexis. Redige un briefing vocal court en francais, lu a voix haute par une enceinte : pas de markdown, pas de listes a puces, des phrases simples.

Donne d'abord la meteo du jour a Strasbourg en une phrase. Puis l'agenda : annonce les rendez-vous d'aujourd'hui dans l'ordre, avec l'heure et l'intitule (s'il n'y en a aucun, dis-le). Ensuite les mails importants. Termine par une phrase sur Formaze : ${dlFormaze} telechargements au total sur NuGet.

Pour les mails, ne retiens QUE ce qui compte vraiment : vraies personnes qui s'adressent a lui (surtout si une reponse est attendue), actions ou echeances, sujets pro/opportunites/reseau/candidatures/clients, argent (factures, paiements, banque). IGNORE : codes 2FA et notifications de connexion, newsletters/promos/alertes emploi automatiques, accuses de reception, reseaux sociaux. Si aucun mail n'est notable, dis-le en une phrase.

Meteo du jour (Strasbourg):
${meteo}

Agenda du jour:
${lignesAgenda || 'Aucun rendez-vous.'}

Mails (24h):
${lignesMails || 'Aucun mail.'}

Telechargements Formaze (total NuGet): ${dlFormaze}`;
return [{ json: { prompt, count: mails.length + events.length } }];
